+  let orderRepo: OrderRepository;
+  let userRepo: UserRepository;
+  let analyticsService: AnalyticsService;
+  let handler: AnalyticsRouteHandler;
+
+  // Seed data covering two time periods for comparison:
+  // Current period:  2026-03-01 to 2026-03-31
+  // Previous period: 2026-01-29 to 2026-02-28
+
+  const users = [
+    makeUser('u1', 'Alice'),
+    makeUser('u2', 'Bob'),
+    makeUser('u3', 'Charlie'),
+  ];
+
+  const currentPeriodOrders = [
+    makeOrder('o1', 'u1', 100, 'delivered', '2026-03-05'),
+    makeOrder('o2', 'u1', 200, 'delivered', '2026-03-10'),
+    makeOrder('o3', 'u2', 150, 'shipped', '2026-03-15'),
+    makeOrder('o4', 'u3', 50, 'pending', '2026-03-20'),
+    makeOrder('o5', 'u1', 300, 'confirmed', '2026-03-25'),
+  ];
+
+  const previousPeriodOrders = [
+    makeOrder('o6', 'u1', 80, 'delivered', '2026-02-05'),
+    makeOrder('o7', 'u2', 120, 'delivered', '2026-02-15'),
+  ];
+
+  beforeEach(() => {
+    db = new Database();
+    orderRepo = new OrderRepository(db);
+    userRepo = new UserRepository(db);
+    analyticsService = new AnalyticsService(orderRepo, userRepo);
+    handler = new AnalyticsRouteHandler(analyticsService);
+
+    // Seed users
+    for (const user of users) {
+      userRepo.save(user);
+    }
+
+    // Seed orders
+    for (const order of [...currentPeriodOrders, ...previousPeriodOrders]) {
+      orderRepo.save(order);
+    }
+  });
+
+  // -------------------------------------------------------------------------
+  // Dashboard endpoint
+  // -------------------------------------------------------------------------
+
+  describe('GET /api/analytics/dashboard', () => {
+    it('should return full dashboard data with all metrics', async () => {
+      const result = await handler.getDashboard({
+        start: '2026-03-01',
+        end: '2026-03-31',
+        granularity: 'day',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.status).toBe(200);
+      expect(result.data).toBeDefined();
+
+      const data = result.data!;
+      expect(data.metrics).toHaveLength(4);
+
+      // Check metric types are all present
+      const metricTypes = data.metrics.map((m) => m.type);
+      expect(metricTypes).toContain('revenue');
+      expect(metricTypes).toContain('orders');
+      expect(metricTypes).toContain('users');
+      expect(metricTypes).toContain('conversion');
+
+      // Revenue metric: 100 + 200 + 150 + 50 + 300 = 800
+      const revenue = data.metrics.find((m) => m.type === 'revenue')!;
+      expect(revenue.currentValue).toBe(800);
+
+      // Orders metric: 5
+      const orders = data.metrics.find((m) => m.type === 'orders')!;
+      expect(orders.currentValue).toBe(5);
+
+      // Users metric: 3 distinct users
+      const usersMetric = data.metrics.find((m) => m.type === 'users')!;
+      expect(usersMetric.currentValue).toBe(3);
+
+      // Order status breakdown
+      expect(data.orderStatusBreakdown.length).toBeGreaterThan(0);
+
+      // Top users
+      expect(data.topUsers.length).toBeGreaterThan(0);
+      // Alice should be top (100 + 200 + 300 = 600)
+      expect(data.topUsers[0].userId).toBe('u1');
+      expect(data.topUsers[0].totalRevenue).toBe(600);
+
+      // generatedAt should be recent
+      expect(data.generatedAt).toBeInstanceOf(Date);
+    });
+
+    it('should include previous period comparison in metrics', async () => {
+      const result = await handler.getDashboard({
+        start: '2026-03-01',
+        end: '2026-03-31',
+      });
+
+      const data = result.data!;
+      const revenue = data.metrics.find((m) => m.type === 'revenue')!;
+
+      // Previous period: o6(80) + o7(120) = 200
+      expect(revenue.previousValue).toBe(200);
+      expect(revenue.trend).toBe('up');
+      expect(revenue.changePercent).toBe(300); // (800-200)/200 * 100
+    });
+
+    it('should include time series data points', async () => {
+      const result = await handler.getDashboard({
+        start: '2026-03-01',
+        end: '2026-03-31',
+        granularity: 'week',
+      });
+
+      const data = result.data!;
+      const revenue = data.metrics.find((m) => m.type === 'revenue')!;
+      expect(revenue.timeSeries.length).toBeGreaterThan(0);
+
+      // Each point should have timestamp, value, label
+      for (const point of revenue.timeSeries) {
+        expect(point.timestamp).toBeInstanceOf(Date);
+        expect(typeof point.value).toBe('number');
+        expect(typeof point.label).toBe('string');
+      }
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // Metric detail endpoint
+  // -------------------------------------------------------------------------
+
+  describe('GET /api/analytics/metrics/:type', () => {
+    it('should return revenue metric detail', async () => {
+      const result = await handler.getMetricDetail({
+        start: '2026-03-01',
+        end: '2026-03-31',
+        type: 'revenue',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.data).toBeDefined();
+      expect(result.data!.metric.type).toBe('revenue');
+      expect(result.data!.metric.currentValue).toBe(800);
+    });
+
+    it('should return orders metric detail', async () => {
+      const result = await handler.getMetricDetail({
+        start: '2026-03-01',
+        end: '2026-03-31',
+        type: 'orders',
+      });
+
+      expect(result.data!.metric.type).toBe('orders');
+      expect(result.data!.metric.currentValue).toBe(5);
+    });
+
+    it('should return users metric detail', async () => {
+      const result = await handler.getMetricDetail({
+        start: '2026-03-01',
+        end: '2026-03-31',
+        type: 'users',
+      });
+
+      expect(result.data!.metric.type).toBe('users');
+      expect(result.data!.metric.currentValue).toBe(3);
+    });
+
+    it('should return conversion metric detail', async () => {
+      const result = await handler.getMetricDetail({
+        start: '2026-03-01',
+        end: '2026-03-31',
+        type: 'conversion',
+      });
+
+      expect(result.data!.metric.type).toBe('conversion');
+      // 5 orders / 3 users = 1.67
+      expect(result.data!.metric.currentValue).toBeCloseTo(1.67, 1);
+    });
+
+    it('should return error for invalid metric type', async () => {
+      const result = await handler.getMetricDetail({
+        start: '2026-03-01',
+        end: '2026-03-31',
+        type: 'invalid',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.status).toBe(400);
+      expect(result.error).toContain('Invalid metric type');
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // Order status breakdown endpoint
+  // -------------------------------------------------------------------------
+
+  describe('GET /api/analytics/orders/status', () => {
+    it('should return order status breakdown', async () => {
+      const result = await handler.getOrderStatusBreakdown({
+        start: '2026-03-01',
+        end: '2026-03-31',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.data).toBeDefined();
+      expect(result.data!.totalOrders).toBe(5);
+
+      const breakdown = result.data!.breakdown;
+      // We have: 2 delivered, 1 shipped, 1 pending, 1 confirmed
+      const delivered = breakdown.find((b) => b.status === 'delivered');
+      expect(delivered).toBeDefined();
+      expect(delivered!.count).toBe(2);
+      expect(delivered!.percentage).toBe(40);
+
+      // All percentages should sum to 100
+      const totalPercentage = breakdown.reduce(
+        (sum, b) => sum + b.percentage,
+        0,
+      );
+      expect(totalPercentage).toBeCloseTo(100, 0);
+    });
+
+    it('should return empty breakdown for time range with no orders', async () => {
+      const result = await handler.getOrderStatusBreakdown({
+        start: '2025-01-01',
+        end: '2025-01-31',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.data!.totalOrders).toBe(0);
+      expect(result.data!.breakdown).toHaveLength(0);
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // Top users endpoint
+  // -------------------------------------------------------------------------
+
+  describe('GET /api/analytics/users/top', () => {
+    it('should return top users ranked by revenue', async () => {
+      const result = await handler.getTopUsers({
+        start: '2026-03-01',
+        end: '2026-03-31',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.data).toBeDefined();
+
+      const topUsers = result.data!.users;
+      expect(topUsers.length).toBe(3);
+
+      // Alice: 600, Bob: 150, Charlie: 50
+      expect(topUsers[0].userId).toBe('u1');
+      expect(topUsers[0].userName).toBe('Alice');
+      expect(topUsers[0].totalRevenue).toBe(600);
+      expect(topUsers[0].orderCount).toBe(3);
+
+      expect(topUsers[1].userId).toBe('u2');
+      expect(topUsers[1].totalRevenue).toBe(150);
+
+      expect(topUsers[2].userId).toBe('u3');
+      expect(topUsers[2].totalRevenue).toBe(50);
+    });
+
+    it('should respect the limit parameter', async () => {
+      const result = await handler.getTopUsers({
+        start: '2026-03-01',
+        end: '2026-03-31',
+        limit: '2',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.data!.users).toHaveLength(2);
+      expect(result.data!.limit).toBe(2);
+    });
+
+    it('should return error for invalid limit', async () => {
+      const result = await handler.getTopUsers({
+        start: '2026-03-01',
+        end: '2026-03-31',
+        limit: '-1',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.status).toBe(400);
+      expect(result.error).toContain('Invalid limit');
+    });
+
+    it('should return error for non-numeric limit', async () => {
+      const result = await handler.getTopUsers({
+        start: '2026-03-01',
+        end: '2026-03-31',
+        limit: 'abc',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.status).toBe(400);
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // Error scenarios
+  // -------------------------------------------------------------------------
+
+  describe('Error handling', () => {
+    it('should return error for missing start date', async () => {
+      const result = await handler.getDashboard({
+        start: '',
+        end: '2026-03-31',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.status).toBe(400);
+    });
+
+    it('should return error for invalid start date', async () => {
+      const result = await handler.getDashboard({
+        start: 'not-a-date',
+        end: '2026-03-31',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.status).toBe(400);
+      expect(result.error).toContain('Invalid start date');
+    });
+
+    it('should return error for invalid end date', async () => {
+      const result = await handler.getDashboard({
+        start: '2026-03-01',
+        end: 'not-a-date',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.status).toBe(400);
+      expect(result.error).toContain('Invalid end date');
