+
+      expect(result.success).toBe(false);
+      expect(result.status).toBe(400);
+      expect(result.error).toContain('Invalid granularity');
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // Time-range filtering
+  // -------------------------------------------------------------------------
+
+  describe('Time-range filtering', () => {
+    it('should only include orders within the specified range', async () => {
+      // Query only first half of March — should only get o1 and o2
+      const result = await handler.getMetricDetail({
+        start: '2026-03-01',
+        end: '2026-03-12',
+        type: 'orders',
+      });
+
+      expect(result.data!.metric.currentValue).toBe(2);
+    });
+
+    it('should return zero metrics for empty time range', async () => {
+      const result = await handler.getMetricDetail({
+        start: '2025-06-01',
+        end: '2025-06-30',
+        type: 'revenue',
+      });
+
+      expect(result.data!.metric.currentValue).toBe(0);
+    });
+
+    it('should handle granularity: hour', async () => {
+      const result = await handler.getDashboard({
+        start: '2026-03-05T00:00:00Z',
+        end: '2026-03-05T23:59:59Z',
+        granularity: 'hour',
+      });
+
+      expect(result.success).toBe(true);
+      const revenue = result.data!.metrics.find((m) => m.type === 'revenue')!;
+      // Should have ~24 time series points for hourly granularity
+      expect(revenue.timeSeries.length).toBeGreaterThanOrEqual(23);
+    });
+
+    it('should handle granularity: month', async () => {
+      const result = await handler.getDashboard({
+        start: '2026-01-01',
+        end: '2026-06-30',
+        granularity: 'month',
+      });
+
+      expect(result.success).toBe(true);
+      const revenue = result.data!.metrics.find((m) => m.type === 'revenue')!;
+      expect(revenue.timeSeries.length).toBeGreaterThanOrEqual(6);
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // Parsing helpers (unit-level but included for completeness)
+  // -------------------------------------------------------------------------
+
+  describe('parseAnalyticsQuery', () => {
+    it('should parse valid params with defaults', () => {
+      const query = parseAnalyticsQuery({
+        start: '2026-03-01',
+        end: '2026-03-31',
+      });
+
+      expect(query.timeRange.start).toEqual(new Date('2026-03-01'));
+      expect(query.timeRange.end).toEqual(new Date('2026-03-31'));
+      expect(query.granularity).toBe('day');
+    });
+
+    it('should accept explicit granularity', () => {
+      const query = parseAnalyticsQuery({
+        start: '2026-03-01',
+        end: '2026-03-31',
+        granularity: 'week',
+      });
+
+      expect(query.granularity).toBe('week');
+    });
+  });
+
+  describe('parseMetricType', () => {
+    it('should accept valid metric types', () => {
+      expect(parseMetricType('revenue')).toBe('revenue');
+      expect(parseMetricType('orders')).toBe('orders');
+      expect(parseMetricType('users')).toBe('users');
+      expect(parseMetricType('conversion')).toBe('conversion');
+    });
+
+    it('should throw for invalid metric type', () => {
+      expect(() => parseMetricType('invalid')).toThrow('Invalid metric type');
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // Service-level integration (bypassing routes)
+  // -------------------------------------------------------------------------
+
+  describe('AnalyticsService direct', () => {
+    it('should compute dashboard with trend comparison', async () => {
+      const query = parseAnalyticsQuery({
+        start: '2026-03-01',
+        end: '2026-03-31',
+      });
+
+      const dashboard = await analyticsService.getDashboard(query);
+
+      expect(dashboard.metrics).toHaveLength(4);
+      expect(dashboard.orderStatusBreakdown.length).toBeGreaterThan(0);
+      expect(dashboard.topUsers.length).toBeGreaterThan(0);
+      expect(dashboard.query).toEqual(query);
+    });
+
+    it('should handle order status breakdown with all statuses', async () => {
+      const query = parseAnalyticsQuery({
+        start: '2026-03-01',
+        end: '2026-03-31',
+      });
+
+      const result = await analyticsService.getOrderStatusBreakdown(query);
+
+      // Verify all percentages sum to 100
+      const total = result.breakdown.reduce((s, b) => s + b.percentage, 0);
+      expect(total).toBeCloseTo(100, 0);
+
+      // Verify sorted by count descending
+      for (let i = 1; i < result.breakdown.length; i++) {
+        expect(result.breakdown[i].count).toBeLessThanOrEqual(
+          result.breakdown[i - 1].count,
+        );
+      }
+    });
+
+    it('should compute top users with correct user names', async () => {
+      const query = parseAnalyticsQuery({
+        start: '2026-03-01',
+        end: '2026-03-31',
+      });
+
+      const result = await analyticsService.getTopUsers(query, 10);
+
+      for (const user of result.users) {
+        expect(user.userName).not.toBe('Unknown');
+        expect(user.orderCount).toBeGreaterThan(0);
+        expect(user.totalRevenue).toBeGreaterThan(0);
+      }
+    });
+  });
+});

